DROP TABLE IF EXISTS `prompt_template`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `prompt_template` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `templateName` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '模板名称',
  `matchIdentity` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '匹配身份，NULL表示不限',
  `matchIndustry` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '匹配行业领域，NULL表示不限',
  `description` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '模板描述',
  `promptContent` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '提示词内容（含占位符{{key}}）',
  `templateFields` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '模板可编辑字段定义（JSON数组）',
  `sortOrder` int NOT NULL DEFAULT '0' COMMENT '排序权重（越小越靠前）',
  `isEnabled` tinyint NOT NULL DEFAULT '1' COMMENT '是否启用',
  `userId` bigint DEFAULT NULL COMMENT '创建人id',
  `createTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint NOT NULL DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  KEY `idx_matchIdentity` (`matchIdentity`),
  KEY `idx_matchIndustry` (`matchIndustry`),
  KEY `idx_sortOrder` (`sortOrder`)
) ENGINE=InnoDB AUTO_INCREMENT=36 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='提示词模板';
