seText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"个体\"}]',1,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(29,'医疗机构官网','enterprise','医疗/健康','医疗机构品牌形象与科室介绍站点','为一家{{identity}}医疗/健康机构创建官方展示静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含机构简介与资质展示、科室导航卡片（含图标和简介）、专家团队（头像+职称+擅长方向）、服务数据量化（接诊量、满意度等数字动效）、就医指南FAQ折叠面板、联系方式区域。{{logoOption}}页面需有滚动渐入动效。所有内容使用真实可信的医疗场景文本。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"医疗蓝(#0277bd+#e1f5fe)\",\"信任绿(#2e7d32+#e8f5e9)\",\"洁净白蓝(#fff+#42a5f5)\",\"温馨暖白(#fafafa+#ff8a65)\"],\"defaultValue\":\"医疗蓝(#0277bd+#e1f5fe)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"经典单页滚动\",\"模块分区卡片\",\"顶部大图+信息区\"],\"defaultValue\":\"经典单页滚动\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为网站设计一个医疗机构风格的SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"企业\"}]',2,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(30,'美食店铺主页','merchant','餐饮/美食','餐饮商户菜品展示与店铺介绍页','为一位{{identity}}餐饮/美食商户创建美食店铺展示静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含店铺招牌Banner（含营业时间）、招牌菜品大图网格（含菜名和价格）、菜品分类标签筛选、门店故事与厨师介绍、顾客好评轮播、门店数据（日均客流、好评率等）。{{logoOption}}页面需有菜品卡片悬浮和图片放大动效。所有内容使用真实可信的餐饮场景数据。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"食欲红(#c62828+#ffebee)\",\"自然棕绿(#33691e+#f1f8e9)\",\"温暖橙黄(#e65100+#fff8e1)\",\"雅致黑红(#212121+#ef5350)\"],\"defaultValue\":\"食欲红(#c62828+#ffebee)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"美食图片网格\",\"菜单列表风格\",\"大图轮播+分区\"],\"defaultValue\":\"美食图片网格\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为网站设计一个美食主题的SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"商户\"}]',1,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(31,'企业财务报表展示','enterprise','金融/财务','企业财务